// --------------- C solution (offline 2‑D Fenwick) ---------------
#include <stdio.h>
#include <stdlib.h>

typedef struct {int x, y, s;} Point;
typedef struct {int x, y, d, id; long long limit; int ans;} Query;

// ---------- simple dynamic array ----------
typedef struct {int *a; int sz, cap;} IntVec;
void iv_init(IntVec *v){v->a=NULL;v->sz=0;v->cap=0;}
void iv_push(IntVec *v,int val){if(v->sz==v->cap){v->cap=v->cap?v->cap*2:4;v->a=realloc(v->a,v->cap*sizeof(int));}v->a[v->sz++]=val;}
int cmp_int(const void *a,const void *b){return *(int*)a-*(int*)b;}

// ---------- Fenwick tree of vectors ----------
int MAXX = 300000 + 5;
IntVec ft[MAXX];
int Nglobal;

void ft_add_point(int x,int y){for(int i=x;i<=Nglobal;i+=i&-i){iv_push(&ft[i], y);} }

int ft_query(int x,int y){int res=0;for(int i=x;i>0;i-=i&-i){int *arr=ft[i].a;int lo=0,hi=ft[i].sz;while(lo<hi){int mid=(lo+hi)/2; if(arr[mid]<=y) lo=mid+1; else hi=mid;}res+=lo;}return res;}

int rect_query(int x1,int y1,int x2,int y2){ // inclusive
    if(x1> x2 || y1> y2) return 0;
    return ft_query(x2,y2)-ft_query(x1-1,y2)-ft_query(x2,y1-1)+ft_query(x1-1,y1-1);
}

int cmp_point(const void *a,const void *b){return ((Point*)a)->s-((Point*)b)->s;}
int cmp_query(const void *a,const void *b){long long da=((Query*)a)->limit, db=((Query*)b)->limit; return da<db?-1:da>db?1:0;}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d",&N,&Q);
        Point *pts = (Point*)malloc(N*sizeof(Point));
        for(int i=0;i<N;i++){
            int xi,yi; scanf("%d %d",&xi,&yi);
            pts[i].x=xi; pts[i].y=yi; pts[i].s=xi+yi;
        }
        Query *qs = (Query*)malloc(Q*sizeof(Query));
        for(int i=0;i<Q;i++){
            int x,y,d; scanf("%d %d %d",&x,&y,&d);
            qs[i].x=x; qs[i].y=y; qs[i].d=d; qs[i].id=i; qs[i].limit = (long long)x + y + d;
        }
        // coordinate compression for x (Fenwick size)
        int maxX=0; for(int i=0;i<N;i++) if(pts[i].x>maxX) maxX=pts[i].x; for(int i=0;i<Q;i++) if(qs[i].x+qs[i].d>maxX) maxX=qs[i].x+qs[i].d; Nglobal = maxX+2;
        // clear ft vectors
        for(int i=0;i<=Nglobal;i++){free(ft[i].a); ft[i].a=NULL; ft[i].sz=ft[i].cap=0;}
        // collect y values for each ft node (offline building)
        // first pass: add all points that will ever be inserted (all points)
        for(int i=0;i<N;i++) ft_add_point(pts[i].x, pts[i].y);
        // second pass: also add rectangle borders from queries (x2 and y2) to guarantee they exist in vectors
        for(int i=0;i<Q;i++){
            int x2 = qs[i].x + qs[i].d;
            int y2 = qs[i].y + qs[i].d;
            ft_add_point(x2, y2);
        }
        // sort and deduplicate each vector, then replace with BIT array (initially zero)
        for(int i=1;i<=Nglobal;i++) if(ft[i].sz){ qsort(ft[i].a, ft[i].sz, sizeof(int), cmp_int); int w=0; for(int j=0;j<ft[i].sz;j++) if(j==0||ft[i].a[j]!=ft[i].a[j-1]) ft[i].a[w++]=ft[i].a[j]; ft[i].sz=w; ft[i].a = realloc(ft[i].a, (w+2)*sizeof(int)); }
        // sort points and queries by sum limit
        qsort(pts,N,sizeof(Point),cmp_point);
        qsort(qs,Q,sizeof(Query),cmp_query);
        // BIT for counts (same structure as ft but stores int counts)
        // we reuse ft vectors as index maps; we need a parallel array of counts per node
        int **bit = (int**)malloc((Nglobal+1)*sizeof(int*));
        for(int i=1;i<=Nglobal;i++) if(ft[i].sz) bit[i]=(int*)calloc(ft[i].sz+1,sizeof(int)); else bit[i]=NULL;
        // helper to update a point in 2‑D BIT
        void update2D(int x,int y,int delta){ for(int i=x;i<=Nglobal;i+=i&-i){ int *arr=ft[i].a; int lo=0,hi=ft[i].sz; while(lo<hi){int mid=(lo+hi)/2; if(arr[mid]<=y) lo=mid+1; else hi=mid;} int pos=lo; for(int j=pos;j<=ft[i].sz;j+=j&-j) bit[i][j]+=delta; } };
        // helper to query prefix
        int query2D(int x,int y){ int res=0; for(int i=x;i>0;i-=i&-i){ int *arr=ft[i].a; int lo=0,hi=ft[i].sz; while(lo<hi){int mid=(lo+hi)/2; if(arr[mid]<=y) lo=mid+1; else hi=mid;} int pos=lo; for(int j=pos;j>0;j-=j&-j) res+=bit[i][j]; } return res; };
        // process
        int pIdx=0;
        for(int qi=0; qi<Q; ++qi){
            while(pIdx<N && pts[pIdx].s <= qs[qi].limit){
                update2D(pts[pIdx].x, pts[pIdx].y, 1);
                ++pIdx;
            }
            int x1 = qs[qi].x;
            int y1 = qs[qi].y;
            int x2 = qs[qi].x + qs[qi].d;
            int y2 = qs[qi].y + qs[qi].d;
            int ans = query2D(x2, y2) - query2D(x1-1, y2) - query2D(x2, y1-1) + query2D(x1-1, y1-1);
            qs[qi].ans = ans;
        }
        // restore original order and output
        int *out = (int*)malloc(Q*sizeof(int));
        for(int i=0;i<Q;i++) out[qs[i].id]=qs[i].ans;
        for(int i=0;i<Q;i++) printf("%d\n", out[i]);
        // free
        free(pts); free(qs); free(out);
        for(int i=1;i<=Nglobal;i++) free(bit[i]); free(bit);
    }
    return 0;
}
